def verify_message_signature(message_body: str, signature: Optional[str]) -> bool:
    """Verify HMAC-SHA256 signature to ensure message integrity and authenticity."""
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY")
    if not signing_key:
        logging.warning("MESSAGE_SIGNING_KEY not configured — rejecting message")
        return False
    if not signature:
        return False

    expected = hmac.new(
        signing_key.encode("utf-8"),
        message_body.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    return hmac.compare_digest(expected, signature)


